  ('elementary-d0d1b9a2-moex-00365', 'elementary-d0d1b9a2', 'elementary-d0d1b9a2-moex-113-dca36ed8', 'sub-elementary-d0d1b9a2-04', NULL, 'single_choice', '審計人員為行使職權，向各機關查閱簿籍、憑證或其他文件，或檢查現金、財物時，各該主管人員不得隱 匿或拒絕；遇有疑問，或需要有關資料，並應為詳實之答復或提供之。如有違背前項規定，審計人員應將 其事實報告該管審計機關，通知各該機關長官予以處分，或呈請何者核辦？', '["審計部", "行政院", "司法院", "監察院"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:46+00:00", "source_pdf_sha1": "fa35e34230b5", "answer_pdf_sha1": "290cd2551a74", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "508", "s": "0502", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "會計審計法規大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 45, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "會計"}'::jsonb, NULL),
  ('elementary-d0d1b9a2-moex-00366', 'elementary-d0d1b9a2', 'elementary-d0d1b9a2-moex-113-dca36ed8', 'sub-elementary-d0d1b9a2-04', NULL, 'single_choice', '各機關對於審計機關之聲復決定不服時，除決算之審定依決算法之規定辦理外，得自接到通知之日起幾日 內聲請覆議？且以幾次為限？', '["30日、1次為限", "30日、2次為限", "10日、1次為限", "10日、2次為限"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:46+00:00", "source_pdf_sha1": "fa35e34230b5", "answer_pdf_sha1": "290cd2551a74", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "508", "s": "0502", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "會計審計法規大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 46, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "會計"}'::jsonb, NULL),
  ('elementary-d0d1b9a2-moex-00367', 'elementary-d0d1b9a2', 'elementary-d0d1b9a2-moex-113-dca36ed8', 'sub-elementary-d0d1b9a2-04', NULL, 'single_choice', '依會計法之規定，主辦會計人員，應自後任接替之日起的幾日之內交代清楚，非取得交代證明書後，不得 擅離任所？後任接受移交時，應即會同監交人員，於幾日之內依據移交表或目錄，逐項點收清楚，出具交 代證明書？', '["4日、3日", "4日、2日", "5日、3日", "5日、2日"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:46+00:00", "source_pdf_sha1": "fa35e34230b5", "answer_pdf_sha1": "290cd2551a74", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "508", "s": "0502", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "會計審計法規大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 47, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "會計"}'::jsonb, NULL),
  ('elementary-d0d1b9a2-moex-00368', 'elementary-d0d1b9a2', 'elementary-d0d1b9a2-moex-113-dca36ed8', 'sub-elementary-d0d1b9a2-04', NULL, 'single_choice', '各機關長官或其授權代簽人及下列何者簽證各項支出時，對於審計有關法令，遇有疑義或爭執時，得以書 面向該管審計機關諮詢？', '["業務之主管", "主辦會計人員", "會計佐理人員", "財務出納人員"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:46+00:00", "source_pdf_sha1": "fa35e34230b5", "answer_pdf_sha1": "290cd2551a74", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "508", "s": "0502", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "會計審計法規大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 48, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "會計"}'::jsonb, NULL),
  ('elementary-d0d1b9a2-moex-00369', 'elementary-d0d1b9a2', 'elementary-d0d1b9a2-moex-113-dca36ed8', 'sub-elementary-d0d1b9a2-04', NULL, 'single_choice', '審計人員發覺各機關人員有財務上不法或不忠於職務上之行為，應報告該管審計機關，通知各該機關長官 處分之，並得由審計機關報請何者依法處理？其涉及刑事者，應移送法院辦理，並報告於何者？', '["監察院、監察院", "行政院、監察院", "行政院、司法院", "監察院、司法院"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:46+00:00", "source_pdf_sha1": "fa35e34230b5", "answer_pdf_sha1": "290cd2551a74", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "508", "s": "0502", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "會計審計法規大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 49, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "會計"}'::jsonb, NULL),
  ('elementary-d0d1b9a2-moex-00370', 'elementary-d0d1b9a2', 'elementary-d0d1b9a2-moex-113-dca36ed8', 'sub-elementary-d0d1b9a2-04', NULL, 'single_choice', '依審計法有關財物審計之規定，下列敘述何者錯誤？', '["各機關對於所經管之不動產、物品或其他財產之增減、保管、移轉、處理等事務，應按會計法及其他有 關法令之規定，編製有關財物會計報告，依限送審計機關審核", "各機關對於所經管之財物，依照規定使用年限，已達報廢程度時，必須報廢，其在一定金額以上者，應 報審計機關查核", "在一定金額以上不能利用之廢品，及已屆保管年限之會計憑證、簿籍、報表等，依照法令規定可予銷燬 時，應徵得主計機關同意後為之", "各機關經管現金、票據、證券、財物或其他資產，如有遺失、毀損，或因其他意外事故而致損失者，應 檢同有關證件，報審計機關審核"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:46+00:00", "source_pdf_sha1": "fa35e34230b5", "answer_pdf_sha1": "290cd2551a74", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "508", "s": "0502", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "會計審計法規大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 50, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "會計"}'::jsonb, NULL),
  ('elementary-d0d1b9a2-moex-00371', 'elementary-d0d1b9a2', 'elementary-d0d1b9a2-moex-112-b3f42868', 'sub-elementary-d0d1b9a2-01', NULL, 'single_choice', '一國面對景氣衰退時，政府往往會透過某些措施的採行，刺激景氣復甦，帶動經濟成長。下列何者無法 達成刺激景氣復甦的目標？', '["增加公共投資", "降低重貼現率", "獎勵民間投資", "取消補貼政策"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:46+00:00", "source_pdf_sha1": "ea35e40f9519", "answer_pdf_sha1": "d51770cddb1b", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "507", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "會計"}'::jsonb, NULL),
  ('elementary-d0d1b9a2-moex-00372', 'elementary-d0d1b9a2', 'elementary-d0d1b9a2-moex-112-b3f42868', 'sub-elementary-d0d1b9a2-01', NULL, 'single_choice', '若世界僅由甲、乙兩國組成，且甲國生產所有商品的效率皆比乙國的水準高。若以機會成本的觀點而言， 下列有關甲、乙兩國生產及貿易的敘述，何者正確？', '["甲國生產所有商品均具絕對利益", "乙國向甲國進口所有產品最有利", "甲國生產所有商品的機會成本低於乙國", "若兩國進行分工，甲、乙兩國的生產可能線會內縮"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:46+00:00", "source_pdf_sha1": "ea35e40f9519", "answer_pdf_sha1": "d51770cddb1b", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "507", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "會計"}'::jsonb, NULL),
  ('elementary-d0d1b9a2-moex-00373', 'elementary-d0d1b9a2', 'elementary-d0d1b9a2-moex-112-b3f42868', 'sub-elementary-d0d1b9a2-01', NULL, 'single_choice', '大學剛畢業的小湘有三個工作機會與繼續升學的道路可選擇，一是月薪2萬5千元的家教老師；另一是 月薪2萬8千元的房屋仲介；以及月薪3萬元的法務助理；若選擇不就業，繼續進入研究所碩士班就讀， 學雜費兩年共需20萬元。依上述資料判斷，在不考慮其他條件的情況下，針對小湘大學畢業後兩年間做 選擇的機會成本之敘述，下列何者正確？', '["若當家教老師，機會成本為67萬2千元", "若選擇當房屋仲介，外顯成本為72萬元", "若選擇就學，外顯成本為72萬元", "若選擇就學，機會成本為92萬元"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:46+00:00", "source_pdf_sha1": "ea35e40f9519", "answer_pdf_sha1": "d51770cddb1b", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "507", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "會計"}'::jsonb, NULL),
  ('elementary-d0d1b9a2-moex-00374', 'elementary-d0d1b9a2', 'elementary-d0d1b9a2-moex-112-b3f42868', 'sub-elementary-d0d1b9a2-01', NULL, 'single_choice', '從塑化劑事件到毒澱粉，食安危機連環爆，連許多老店與大公司的知名產品都因使用有害人體健康的原 料，使消費者人人自危，深怕吃下肚的是黑心商品。許多產品銷售成績一落千丈，對加工食品業的業績 有負面影響。上述事件使消費者對加工食品需求的影響，下列何者正確？', '["預期加工食品價格會下跌，導致其需求曲線左移", "消費者對加工食品的偏好降低，導致其需求曲線左移", "加工食品的互補品價格下跌，導致加工食品的需求曲線右移", "天然食材製品的價格上漲，導致加工食品的需求曲線右移"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:46+00:00", "source_pdf_sha1": "ea35e40f9519", "answer_pdf_sha1": "d51770cddb1b", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "507", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "會計"}'::jsonb, NULL)
